// // This module calculates the sum and carry-out for two 1-bit numbers with a carry-in. The sum is the XOR of the inputs, and the carry-out is the OR of the ANDs of the inputs.
module full_adder_1bit(
    input   a,
    input   b,
    input   cin,
    output  sum,
    output  cout
);

assign sum = a ^ b ^ cin;
assign cout = (a & b) | (cin & (a ^ b));

endmodule
